{
  "title": "अंतर्निहित लाइफटाइम",
  "group": "लाइफटाइम एलिजन",
  "options": [
    {
      "text": "कोड सफलतापूर्वक कंपाइल हो जाता है"
    },
    {
      "text": "त्रुटि: लाइफटाइम स्पेसिफायर गायब है",
      "hint": "लाइफटाइम एलिजन के नियमों को याद रखें - वे आपकी मदद के लिए ही हैं!"
    },
    {
      "text": "त्रुटि: स्पष्ट लाइफटाइम आवश्यक है",
      "hint": "कंपाइलर इसे स्वचालित रूप से समझ सकता है"
    },
    {
      "text": "त्रुटि: लाइफटाइम बेमेल है",
      "hint": "यहाँ लाइफटाइम पूरी तरह से संरेखित हैं"
    }
  ],
  "questionProse": [
    "क्या यह कोड कंपाइल होगा? अगर हाँ, तो क्यों? अगर नहीं, तो क्या गड़बड़ है?"
  ],
  "explanationProse": [
    "Rust के लाइफटाइम एलिजन नियमों के कारण यह कोड सफलतापूर्वक कंपाइल हो जाता है। \n      ये नियम कंपाइलर को सामान्य पैटर्न में लाइफटाइम को स्वचालित रूप से अनुमानित करने की अनुमति देते हैं।\n\n      तीन लाइफटाइम एलिजन नियम ये हैं:\n      1. प्रत्येक पैरामीटर को अपना खुद का लाइफटाइम पैरामीटर मिलता है\n      2. यदि केवल एक इनपुट लाइफटाइम पैरामीटर है, तो वह लाइफटाइम सभी आउटपुट लाइफटाइम पैरामीटर्स को असाइन किया जाता है\n      3. यदि कई इनपुट लाइफटाइम पैरामीटर्स हैं, लेकिन उनमें से एक &self या &mut self है, तो self का लाइफटाइम सभी आउटपुट लाइफटाइम पैरामीटर्स को असाइन किया जाता है\n\n      यह फ़ंक्शन इसके बराबर है:",
    "वे सामान्य पैटर्न जहाँ एलिजन काम करता है:",
    "सर्वोत्तम अभ्यास: जब भी संभव हो, एलिजन को अपने लिए काम करने दें, लेकिन यह समझें कि स्पष्ट लाइफटाइम की कब आवश्यकता होती है।"
  ]
}
